package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.IOException;
import java.nio.charset.Charset;
import java.nio.file.Path;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testPrint() throws IOException {
        // Given
        Path path = Path.of("test.csv");
        Charset charset = Charset.defaultCharset();
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        // Mock the CSVPrinter
        CSVPrinter csvPrinter = mock(CSVPrinter.class);
        when(csvFormat.print(any(File.class), any(Charset.class))).thenReturn(csvPrinter);

        // When
        CSVPrinter result = csvFormat.print(path, charset);

        // Then
        assertEquals(csvPrinter, result);
    }
}
